const TASK_POOL: string[] = [
  'chicken', 'cow', 'giant_rat', 'goblin', 'scorpion', 'forest_spider',
  'ice_wolf', 'dire_wolf', 'bear', 'desert_bandit', 'pirate', 'ice_troll',
  'magma_crawler', 'ash_fiend', 'ruin_wraith', 'discord_wisp',
  'hollow_miner', 'manor_revenant',
  // prayer-slayer: the Sundered Choir
  'gravewail_hound', 'choir_ghast', 'dirgewolf', 'dirge_ghoul',
  'chordwyrm', 'carillon_revenant',
];

const REWARDS: Record<string, RewardEntry> = {
  dirge_blade: { id: 'dirge_blade', cost: 120 },
  cull_band: { id: 'cull_band', cost: 60 },
  wardens_visor: { id: 'wardens_visor', cost: 50 },
  tome_of_grudges: { id: 'tome_of_grudges', cost: 25 },
  // prayer-slayer: Cantor Veil's vault
  binding_chime: { id: 'binding_chime', cost: 35 },
  tome_of_dirges: { id: 'tome_of_dirges', cost: 60 },
  silencers_cowl: { id: 'silencers_cowl', cost: 90 },
  silencers_greaves: { id: 'silencers_greaves', cost: 100 },
  silencers_robe: { id: 'silencers_robe', cost: 120 },
  knell_brand: { id: 'knell_brand', cost: 250 },
};

// unsung_helm passive: the Order's helm halves prayer drain.
const helm = (state.equipment as Record<string, { id: string } | null> | undefined)?.head?.id;
if (helm === 'unsung_helm') drain = Math.max(1, Math.ceil(drain / 2));

const eq = state.equipment ?? {};
const fullSilencer = eq.head?.id === 'silencers_cowl' && eq.body?.id === 'silencers_robe' && eq.legs?.id === 'silencers_greaves';
const amount = fullSilencer ? Math.floor(xp * 1.15) : xp;

// protect-prayer damage halving (ward_of_aulden / ward_of_syla / ward_of_quiess / last_verse)
function protectMult(style: 'melee' | 'ranged' | 'magic'): number {
  const want = style === 'melee' ? 'protect_melee' : style === 'ranged' ? 'protect_ranged' : 'protect_magic';
  for (const id of state.player.activePrayers) {
    const def = PRAYERS.find((pr) => pr.id === id);
    if ((def?.boost as string) === want) return 0.5;
  }
  return 1;
}
// in netNpcHitYou: dmg = Math.floor(dmg * protectMult('melee'));
// NOTE: src/defs.ts PRAYERS boost union must widen to include 'protect_melee' | 'protect_ranged' | 'protect_magic'.
